import{_ as d,C as u,o as i,c as p,a2 as r,b as s,w as a,a as t,E as l,a3 as n,j as c}from"./chunks/framework.Bj6f68Cg.js";const P=JSON.parse('{"title":"AgentSecOps Playground","description":"","frontmatter":{},"headers":[],"relativePath":"projects/agentsecops-playground.md","filePath":"projects/agentsecops-playground.md"}'),A={name:"projects/agentsecops-playground.md"};function h(g,e,m,b,E,y){const o=u("Mermaid");return i(),p("div",null,[e[2]||(e[2]=r('<h1 id="agentsecops-playground" tabindex="-1">AgentSecOps Playground <a class="header-anchor" href="#agentsecops-playground" aria-label="Permalink to &quot;AgentSecOps Playground&quot;">​</a></h1><p>Aegis-LLM, SliceRAG와 Mock LLM을 결합해 AI Governance의 보안 불변식을 자동 검증하는 Docker Compose 기반 E2E Harness입니다.</p><h2 id="📌-status-repository" tabindex="-1">📌 Status &amp; Repository <a class="header-anchor" href="#📌-status-repository" aria-label="Permalink to &quot;📌 Status &amp; Repository&quot;">​</a></h2><ul><li><strong>상태</strong>: <code>MVP</code></li><li><strong>저장소 주소</strong>: <a href="https://github.com/devcy0922/agentsecops-playground" target="_blank" rel="noreferrer">GitHub (devcy0922/agentsecops-playground)</a></li><li><strong>라이선스</strong>: MIT</li><li><strong>주요 언어</strong>: Python, Shell, Docker Compose</li></ul><hr><h2 id="_1-problem" tabindex="-1">1. Problem <a class="header-anchor" href="#_1-problem" aria-label="Permalink to &quot;1. Problem&quot;">​</a></h2><p>Gateway, RAG와 LLM Upstream이 각각 정상 동작해도 통합 경계에서 인증 누락, 교차 테넌트 검색, PII 전달, Prompt Injection 우회 또는 Fallback 실패가 발생할 수 있습니다. 실제 API Key와 고객 데이터 없이 이 경계를 반복 검증할 수 있는 안전한 Test Harness가 필요합니다.</p><h2 id="_2-why-i-built-it" tabindex="-1">2. Why I Built It <a class="header-anchor" href="#_2-why-i-built-it" aria-label="Permalink to &quot;2. Why I Built It&quot;">​</a></h2><p>가상 Finance/HR 문서와 Mock LLM을 사용해 Aegis-LLM과 SliceRAG를 실제 Compose Network에서 연결하고, 정상 요청과 보안 실패 경로를 하나의 실행 절차로 검증하기 위해 만들었습니다.</p><h2 id="_3-scope" tabindex="-1">3. Scope <a class="header-anchor" href="#_3-scope" aria-label="Permalink to &quot;3. Scope&quot;">​</a></h2><ul><li>Aegis-LLM, SliceRAG, Mock LLM Compose 통합</li><li>Static Bearer API Key 인증과 정상 Model Request 검증</li><li>Finance/HR Project 간 RAG 격리 검증</li><li>PII 마스킹과 Prompt Injection 조기 차단 검증</li><li>Primary Upstream 실패 후 Fallback 검증</li><li>Audit Log와 Prometheus/Grafana 연결 구성</li></ul><hr><h2 id="_4-architecture" tabindex="-1">4. Architecture <a class="header-anchor" href="#_4-architecture" aria-label="Permalink to &quot;4. Architecture&quot;">​</a></h2>',13)),(i(),s(n,null,{default:a(()=>[l(o,{id:"mermaid-83",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20Test%5B%22E2E%20Verification%20Script%22%5D%20--%3E%20Aegis%5B%22Aegis-LLM%22%5D%0A%20%20%20%20Aegis%20--%3E%20RAG%5B%22SliceRAG%22%5D%0A%20%20%20%20RAG%20--%3E%20DB%5B%22PostgreSQL%20%2B%20pgvector%22%5D%0A%20%20%20%20Aegis%20--%3E%20Primary%5B%22Primary%20Mock%20LLM%22%5D%0A%20%20%20%20Aegis%20-.%20%22Fallback%22%20.-%3E%20Backup%5B%22Backup%20Mock%20LLM%22%5D%0A%20%20%20%20Aegis%20--%3E%20Audit%5B%22JSONL%20Audit%22%5D%0A%20%20%20%20Aegis%20--%3E%20Prometheus%5B%22Prometheus%22%5D%0A%20%20%20%20Prometheus%20--%3E%20Grafana%5B%22Grafana%20Dashboard%22%5D%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[t(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=c("h2",{id:"_5-data-flow",tabindex:"-1"},[t("5. Data Flow "),c("a",{class:"header-anchor",href:"#_5-data-flow","aria-label":'Permalink to "5. Data Flow"'},"​")],-1)),(i(),s(n,null,{default:a(()=>[l(o,{id:"mermaid-87",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20autonumber%0A%20%20%20%20participant%20Test%20as%20Verification%20Script%0A%20%20%20%20participant%20Aegis%0A%20%20%20%20participant%20RAG%20as%20SliceRAG%0A%20%20%20%20participant%20LLM%20as%20Mock%20LLM%0A%20%20%20%20Test-%3E%3ERAG%3A%20Finance%2FHR%20%EA%B0%80%EC%83%81%20%EB%AC%B8%EC%84%9C%20Ingest%0A%20%20%20%20Test-%3E%3EAegis%3A%20Finance%20API%20Key%20%2B%20%EC%A7%88%EB%AC%B8%0A%20%20%20%20Aegis-%3E%3ERAG%3A%20Finance%20project_id%20%EB%B2%94%EC%9C%84%20%EA%B2%80%EC%83%89%0A%20%20%20%20RAG--%3E%3EAegis%3A%20Finance%20Chunk%EB%A7%8C%20%EB%B0%98%ED%99%98%0A%20%20%20%20Aegis-%3E%3ELLM%3A%20RAG%20Context%EB%A5%BC%20%ED%8F%AC%ED%95%A8%ED%95%9C%20%EC%A0%95%EC%A0%9C%20%EC%9A%94%EC%B2%AD%0A%20%20%20%20LLM--%3E%3EAegis%3A%20OpenAI-compatible%20response%0A%20%20%20%20Aegis--%3E%3ETest%3A%20Response%20%2B%20trace_id%0A%20%20%20%20Test-%3E%3ETest%3A%20%EA%B2%A9%EB%A6%AC%2C%20DLP%2C%20%EC%B0%A8%EB%8B%A8%2C%20Fallback%20%EB%8B%A8%EC%96%B8%0A"})]),fallback:a(()=>[...e[1]||(e[1]=[t(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=r('<h2 id="_6-key-design-decisions" tabindex="-1">6. Key Design Decisions <a class="header-anchor" href="#_6-key-design-decisions" aria-label="Permalink to &quot;6. Key Design Decisions&quot;">​</a></h2><ul><li><strong>실제 모델 대신 Mock Upstream 사용</strong>: 테스트 결과가 외부 Provider 상태나 GPU 자원에 의존하지 않도록 요청 수신과 오류를 제어합니다.</li><li><strong>가상 데이터만 사용</strong>: Finance와 HR 경계를 표현하는 합성 문서를 사용해 고객 정보나 운영 Credential 없이 보안 시나리오를 재현합니다.</li><li><strong>실패 경로를 성공 조건에 포함</strong>: 단순 200 응답뿐 아니라 차단 요청이 Upstream에 도달하지 않는지와 Fallback이 사용되는지를 검증합니다.</li></ul><h2 id="_7-security-considerations" tabindex="-1">7. Security Considerations <a class="header-anchor" href="#_7-security-considerations" aria-label="Permalink to &quot;7. Security Considerations&quot;">​</a></h2><ul><li>모든 서비스는 기본적으로 Loopback 또는 Compose 내부 Network에 노출합니다.</li><li>실제 API Key, 고객 문서, 사내 Endpoint를 테스트 Dataset과 Config에 포함하지 않습니다.</li><li>gVisor/eBPF Runtime Sandbox는 현재 저장소의 구현 범위가 아니며 현재 기능으로 주장하지 않습니다.</li></ul><h2 id="_8-observability" tabindex="-1">8. Observability <a class="header-anchor" href="#_8-observability" aria-label="Permalink to &quot;8. Observability&quot;">​</a></h2><ul><li>Aegis Audit Log에서 <code>trace_id</code>, Project, 차단 사유와 Memory 결과를 확인합니다.</li><li>Prometheus와 Grafana Provisioning 설정을 통해 Request와 Block Metric을 시각화할 수 있습니다.</li><li>Test 실패는 어떤 Security Invariant가 깨졌는지 명시적으로 출력합니다.</li></ul><h2 id="_9-technology-stack" tabindex="-1">9. Technology Stack <a class="header-anchor" href="#_9-technology-stack" aria-label="Permalink to &quot;9. Technology Stack&quot;">​</a></h2><ul><li><strong>Orchestration</strong>: Docker Compose, Shell</li><li><strong>Verification</strong>: Python</li><li><strong>Services</strong>: Aegis-LLM, SliceRAG, FastAPI Mock LLM</li><li><strong>Observability</strong>: Prometheus, Grafana, JSONL Audit</li></ul><h2 id="_10-running-locally" tabindex="-1">10. Running Locally <a class="header-anchor" href="#_10-running-locally" aria-label="Permalink to &quot;10. Running Locally&quot;">​</a></h2><p>세 저장소를 같은 상위 디렉터리에 준비한 뒤 실행합니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./run-demo.sh</span></span></code></pre></div><p>실행 스크립트는 Compose를 시작하고 가상 문서를 Ingest한 뒤 보안·격리·Fallback 단언을 수행합니다.</p><h2 id="_11-current-limitations" tabindex="-1">11. Current Limitations <a class="header-anchor" href="#_11-current-limitations" aria-label="Permalink to &quot;11. Current Limitations&quot;">​</a></h2><ul><li>개발용 Compose는 형제 디렉터리의 Aegis-LLM과 SliceRAG Source Build에 의존합니다.</li><li>공개 Release Image의 고정 Tag를 사용하는 독립 실행 구성이 아직 없습니다.</li><li>MCP 고위험 <code>tools/call</code> 차단은 별도 Aperture-MCP 테스트에서 검증하며 현재 Compose에는 포함되지 않습니다.</li></ul><h2 id="_12-next-steps" tabindex="-1">12. Next Steps <a class="header-anchor" href="#_12-next-steps" aria-label="Permalink to &quot;12. Next Steps&quot;">​</a></h2><ul><li>고정 OCI Image Tag를 이용한 독립 실행 Compose 제공</li><li>E2E 결과를 JUnit·JSON Artifact로 출력해 CI Security Gate로 사용</li><li>Network Timeout, Database Restart와 LLM 장애를 포함한 Failure Drill 확대</li></ul>',16))])}const _=d(A,[["render",h]]);export{P as __pageData,_ as default};
